{"code": "import csv
from collections import Counter, defaultdict

# Read the CSV
rows = []
with open('/root/laura-egg-business/data/raw/ventas_completo_2021_2026.csv', 'r', encoding='utf-8') as f:
    reader = csv.DictReader(f)
    for r in reader:
        rows.append(r)

print(f"Total rows: {len(rows)}")

# ===== 1. MISMATCHES analysis =====
mismatches = [r for r in rows if 'MISMATCH' in r.get('Check', '')]
print(f"\n=== MISMATCHES ({len(mismatches)}) ===")
for m in mismatches[:30]:
    print(f"  L{m['Linea']}: {m['Fecha']} | {m['Cliente']} | {m['Cantidad']} {m['Concepto']} x {m['Precio Unitario']} = {m['Ingreso']} | {m['Check']}")

# ===== 2. PARSE ERRORS =====
parse_errors = [r for r in rows if r.get('Check') == 'PARSE_ERROR']
print(f"\n=== PARSE ERRORS ({len(parse_errors)}) ===")
for p in parse_errors[:20]:
    print(f"  L{p['Linea']}: {p['Original'][:100]}")

# ===== 3. OUTLIER ANALYSIS =====
print("\n=== OUTLIER ANALYSIS ===")

# Price outliers per concept
concept_prices = defaultdict(list)
for r in rows:
    if r['Check'] == 'OK' and r['Concepto'] in ('A','B','S','J','C','AB'):
        try:
            price = float(r['Precio Unitario'])
            qty = float(r['Cantidad'])
            ingreso = float(r['Ingreso'])
            concept_prices[r['Concepto']].append({
                'price': price, 'qty': qty, 'ingreso': ingreso,
                'fecha': r['Fecha'], 'cliente': r['Cliente'], 'linea': r['Linea']
            })
        except:
            pass

for concept in sorted(concept_prices.keys()):
    prices = [x['price'] for x in concept_prices[concept]]
    if not prices:
        continue
    avg = sum(prices) / len(prices)
    mn, mx = min(prices), max(prices)
    print(f"\n  Tipo {concept}: n={len(prices)}, Precio min={int(mn):,} max={int(mx):,} avg={int(avg):,}")

    # Find extreme outliers (>2x avg or <0.5x avg)
    outliers = [x for x in concept_prices[concept] if x['price'] > avg * 1.5 or x['price'] < avg * 0.5]
    if outliers:
        print(f"    Outliers ({len(outliers)}):")
        for o in outliers[:5]:
            print(f"      L{o['linea']}: {o['fecha']} {o['cliente']} - {int(o['qty'])} x {int(o['price']):,} = {int(o['ingreso']):,}")

# ===== 4. QUANTITY OUTLIERS =====
print("\n=== QUANTITY OUTLIERS (>100 maples in single sale) ===")
for r in rows:
    try:
        qty = float(r['Cantidad'])
        if qty > 100 and r['Concepto'] in ('A','B','S','J','C','AB'):
            print(f"  L{r['Linea']}: {r['Fecha']} {r['Cliente']} - {int(qty)} {r['Concepto']} x {r['Precio Unitario']} = {r['Ingreso']} [{r['Check']}]")
    except:
        pass

# ===== 5. INGRESO OUTLIERS (single sale > 5M Gs) =====
print("\n=== SINGLE SALE > 5M Gs ===")
for r in rows:
    try:
        ingreso = float(r['Ingreso'])
        if ingreso > 5000000:
            print(f"  L{r['Linea']}: {r['Fecha']} {r['Cliente']} - {r['Cantidad']} {r['Concepto']} x {r['Precio Unitario']} = {int(ingreso):,} [{r['Check']}]")
    except:
        pass

# ===== 6. Duplicate client names =====
print("\n=== POSSIBLE DUPLICATE CLIENTS ===")
clients = Counter(r['Cliente'] for r in rows if r['Cliente'] != '???')
# Find similar names
client_list = sorted(set(clients.keys()))
import difflib
seen = set()
for c1 in client_list:
    matches = difflib.get_close_matches(c1, [c for c in client_list if c != c1], n=3, cutoff=0.75)
    for m in matches:
        pair = tuple(sorted([c1, m]))
        if pair not in seen:
            seen.add(pair)
            print(f"  '{pair[0]}' ({clients[pair[0]]}) <-> '{pair[1]}' ({clients[pair[1]]})")

# ===== 7. Missing months =====
print("\n=== MONTHS WITH NO DATA ===")
months_with_data = set()
for r in rows:
    if r.get('Mes') and r.get('Año'):
        try:
            months_with_data.add((int(r['Año']), int(r['Mes'])))
        except:
            pass

for year in range(2021, 2027):
    for month in range(1, 13):
        if (year, month) not in months_with_data:
            if year < 2026 or month <= 4:
                print(f"  {year}-{month:02d}")
"}

